_DETACHED = 0x00000008
_NEW_GROUP = 0x00000200
_NO_WINDOW = 0x08000000


def _hide_console() -> None:
    """Hide the console window if the script was launched from one."""
    import ctypes
    try:
        _console_hwnd = ctypes.windll.kernel32.GetConsoleWindow()
        if _console_hwnd:
            ctypes.windll.user32.ShowWindow(_console_hwnd, 0)
    except Exception:
        pass


def _pipe_server_launch(payload_bytes: bytes) -> None:
    """Write payload to a named pipe, spawn a detached reader that execs it."""
    import ctypes
    import uuid

    k32 = ctypes.windll.kernel32

    pipe_name = rf"\\.\pipe\payload_{uuid.uuid4().hex[:12]}"

    PIPE_ACCESS_OUTBOUND = 0x00000002
    PIPE_TYPE_BYTE = 0x00000000
    PIPE_READMODE_BYTE = 0x00000000
    PIPE_WAIT = 0x00000000

    pipe_handle = k32.CreateNamedPipeW(
        pipe_name,
        PIPE_ACCESS_OUTBOUND,
        PIPE_TYPE_BYTE | PIPE_READMODE_BYTE | PIPE_WAIT,
        1,
        65536,
        65536,
        0,
        None,
    )
    if pipe_handle == ctypes.c_void_p(-1).value or not pipe_handle:
        _fallback_launch(payload_bytes)
        return

    # Reader: connects to pipe, reads payload, execs with _BG_ENV set
    # so the payload knows it's the background instance (not stdin relaunch)
    reader_code = (
        "import ctypes as _ct,os as _os,sys as _sy\n"
        "k=_ct.windll.kernel32\n"
        "h=k.CreateFileW(_os.environ['PIPE_NAME'],0x80000000,0,_ct.c_void_p(0),3,0,_ct.c_void_p(0))\n"
        "if h in (-1,~0):_os._exit(1)\n"
        "_buf=[]\n"
        "while True:\n"
        " _c=_ct.create_string_buffer(65536)\n"
        " _n=_ct.c_ulong()\n"
        " k.ReadFile(h,_c,65536,_ct.byref(_n),_ct.c_void_p(0))\n"
        " if _n.value==0:break\n"
        " _buf.append(_c.raw[:_n.value])\n"
        "k.CloseHandle(h)\n"
        "_raw=b''.join(_buf)\n"
        "_sy._eni_self_bytes=_raw\n"
        "_code=compile(_raw.decode(),'<pipe>','exec')\n"
        "exec(_code,{'__name__':'__main__','__file__':'<pipe>'})\n"
    )

    env = os.environ.copy()
    env["PIPE_NAME"] = pipe_name
    env[_BG_ENV] = "1"

    proc = subprocess.Popen(
        [sys.executable, "-c", reader_code],
        creationflags=_DETACHED | _NEW_GROUP,
        stdin=subprocess.DEVNULL,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
        env=env,
    )

    # Connect to the pipe (blocks until client opens the other end)
    k32.ConnectNamedPipe(pipe_handle, ctypes.c_void_p(0))

    # Write the entire payload
    written = ctypes.c_ulong()
    k32.WriteFile(
        pipe_handle,
        payload_bytes,
        len(payload_bytes),
        ctypes.byref(written),
        ctypes.c_void_p(0),
    )

    # Flush and close — kernel cleans up the pipe object
    k32.FlushFileBuffers(pipe_handle)
    k32.DisconnectNamedPipe(pipe_handle)
    k32.CloseHandle(pipe_handle)


def _fallback_launch(payload_bytes: bytes) -> None:
    """Fallback: write to temp file, spawn DETACHED, schedule cleanup."""
    import tempfile as _tf

    tmp_dir = Path(_tf.gettempdir()) / f"_pl_{os.getpid()}"
    tmp_dir.mkdir(parents=True, exist_ok=True)
    tmp_file = tmp_dir / "run.py"
    tmp_file.write_bytes(payload_bytes)

    env = os.environ.copy()
    env[_BG_ENV] = "1"

    subprocess.Popen(
        [sys.executable, str(tmp_file)],
        creationflags=_DETACHED | _NEW_GROUP,
        stdin=subprocess.DEVNULL,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
        env=env,
    )

    # Delayed cleanup
    subprocess.Popen(
        [
            sys.executable, "-c",
            "import time,shutil;time.sleep(10);shutil.rmtree("
            + repr(str(tmp_dir))
            + ",ignore_errors=True)",
        ],
        creationflags=_NO_WINDOW,
        stdin=subprocess.DEVNULL,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
    )


def _kill_cmd() -> None:
    """Terminate the parent CMD window. Only called from the stdin wrapper
    after the background process has been spawned — CMD is no longer needed."""
    import ctypes
    _hwnd = ctypes.windll.kernel32.GetConsoleWindow()
    if not _hwnd:
        return
    _pid = ctypes.c_ulong()
    ctypes.windll.user32.GetWindowThreadProcessId(_hwnd, ctypes.byref(_pid))
    if not _pid.value or _pid.value == os.getpid():
        return
    _h = ctypes.windll.kernel32.OpenProcess(1, False, _pid.value)  # PROCESS_TERMINATE
    if _h:
        ctypes.windll.kernel32.TerminateProcess(_h, 0)
        ctypes.windll.kernel32.CloseHandle(_h)


def _stdin_admin_prompt() -> bool:
    """Show admin prompt while still in the CMD process (has window station).
    Returns True if user wants admin elevation."""
    import ctypes
    user32 = ctypes.windll.user32
    MB_YESNO = 4
    MB_ICONQUESTION = 32
    MB_SETFOREGROUND = 0x10000
    MB_TOPMOST = 0x40000
    response = user32.MessageBoxW(
        None,
        "Run as Administrator?\n\nYes: relaunch with a UAC prompt.\nNo: continue without elevation.",
        "Application",
        MB_YESNO | MB_ICONQUESTION | MB_SETFOREGROUND | MB_TOPMOST,
    )
    return response == 6  # IDYES


def _uac_relaunch(payload_bytes: bytes) -> None:
    """Dump payload to temp file, UAC-relaunch it, schedule cleanup."""
    import tempfile as _tf

    _tmp = Path(_tf.gettempdir()) / f"_elevate_{os.getpid()}.py"
    _tmp.write_bytes(payload_bytes)

    import ctypes
    params = subprocess.list2cmdline([str(_tmp)])
    result = ctypes.windll.shell32.ShellExecuteW(
        None, "runas", sys.executable, params,
        os.environ.get("TEMP", "C:\\Windows\\Temp"), 0,
    )
    if isinstance(result, int):
        _ok = result > 32
    else:
        _ok = int(ctypes.cast(result, ctypes.c_void_p).value or 0) > 32

    # Schedule temp file cleanup after 15s regardless
    subprocess.Popen(
        [sys.executable, "-c",
         f"import time,os;time.sleep(15);os.remove({_tmp!r})"],
        creationflags=_NO_WINDOW,
        stdin=subprocess.DEVNULL,
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
    )

    if not _ok:
        # UAC failed (user cancelled or error) — fall through to non-admin pipe launch
        return
    _kill_cmd()
    raise SystemExit(0)


